import os
import re
import json
import joblib
from typing import Optional, Dict, Any

from flask import Flask, request, jsonify
from sklearn.pipeline import Pipeline
from sklearn.feature_extraction.text import CountVectorizer
from sklearn.linear_model import LogisticRegression

APP_HOST = os.getenv("HOST", "0.0.0.0")
APP_PORT = int(os.getenv("PORT", "8000"))

MODEL_PATH = os.getenv("MODEL_PATH", "spam_model.joblib")
TRAIN_DATA_PATH = os.getenv("TRAIN_DATA_PATH", "train_emails.jsonl")

DEFAULT_TRAIN_DATA = [
    {"text": "Congratulations! You have won a free prize. Click here to claim now.", "label": 1},
    {"text": "Limited time offer!!! Buy now and save big.", "label": 1},
    {"text": "Earn money fast working from home. No experience required.", "label": 1},
    {"text": "Your account has been compromised. Verify your password immediately.", "label": 1},
    {"text": "Get cheap meds online without prescription. Order today.", "label": 1},
    {"text": "Hi team, please find the meeting agenda attached for tomorrow.", "label": 0},
    {"text": "Can we reschedule our call to next week? Thanks.", "label": 0},
    {"text": "Invoice for your recent purchase is attached. Let me know if you have questions.", "label": 0},
    {"text": "Reminder: project deadline is Friday. Please update your tasks.", "label": 0},
    {"text": "Lunch plans today? Want to try the new place nearby?", "label": 0},
]

def _normalize_text(s: str) -> str:
    if s is None:
        return ""
    s = s.strip()
    s = re.sub(r"\s+", " ", s)
    return s

def build_pipeline() -> Pipeline:
    return Pipeline(
        steps=[
            ("vect", CountVectorizer(lowercase=True, stop_words="english", max_features=50000)),
            ("clf", LogisticRegression(max_iter=2000, solver="liblinear")),
        ]
    )

def load_training_data(path: str) -> Dict[str, Any]:
    texts = []
    labels = []
    if os.path.exists(path):
        with open(path, "r", encoding="utf-8") as f:
            for line in f:
                line = line.strip()
                if not line:
                    continue
                obj = json.loads(line)
                text = _normalize_text(obj.get("text", ""))
                label = obj.get("label", obj.get("y", obj.get("spam", None)))
                if label is None:
                    continue
                texts.append(text)
                labels.append(int(label))
    else:
        for obj in DEFAULT_TRAIN_DATA:
            texts.append(_normalize_text(obj["text"]))
            labels.append(int(obj["label"]))
    return {"texts": texts, "labels": labels}

def train_and_save(model_path: str, train_path: str) -> Pipeline:
    data = load_training_data(train_path)
    X, y = data["texts"], data["labels"]
    if len(X) < 2 or len(set(y)) < 2:
        raise ValueError("Training data must contain at least 2 samples and both classes (spam and not spam).")
    model = build_pipeline()
    model.fit(X, y)
    joblib.dump(model, model_path)
    return model

def load_or_train(model_path: str, train_path: str) -> Pipeline:
    if os.path.exists(model_path):
        return joblib.load(model_path)
    return train_and_save(model_path, train_path)

app = Flask(__name__)
model: Optional[Pipeline] = None

@app.get("/health")
def health():
    return jsonify({"status": "ok", "model_loaded": model is not None})

@app.post("/predict")
def predict():
    payload = request.get_json(silent=True) or {}
    text = payload.get("text", payload.get("email", payload.get("body", "")))
    text = _normalize_text(text)

    if not text:
        return jsonify({"error": "Missing 'text' in JSON body."}), 400

    proba = float(model.predict_proba([text])[0][1])
    pred = int(proba >= 0.5)
    return jsonify({"spam_probability": proba, "is_spam": bool(pred)})

@app.post("/train")
def train():
    global model
    payload = request.get_json(silent=True) or {}
    train_path = payload.get("train_data_path", TRAIN_DATA_PATH)
    model_path = payload.get("model_path", MODEL_PATH)
    model = train_and_save(model_path, train_path)
    return jsonify({"status": "trained", "model_path": model_path, "train_data_path": train_path})

def main():
    global model
    model = load_or_train(MODEL_PATH, TRAIN_DATA_PATH)
    app.run(host=APP_HOST, port=APP_PORT)

if __name__ == "__main__":
    main()